 20	import { SecretModel } from '@kubevirt-utils/models';
 21	import { getInitialSSHDetails } from '@kubevirt-utils/resources/secret/utils';
 22	import { getNamespace } from '@kubevirt-utils/resources/shared';
 23	import { getVMSSHSecretName } from '@kubevirt-utils/resources/vm';
 24	import { isEmpty } from '@kubevirt-utils/utils/utils';
 25	import { Stack, Text, TextVariants } from '@patternfly/react-core';
 26	
 27	import { removeSSHKeyObject, updateSSHKeyObject } from './sshkey-utils';
 28	
 29	const SSHKey: FC = () => {
 30	  const { t } = useKubevirtTranslation();
 31	  const { tabsData, updateTabsData, updateVM, vm } = useWizardVMContext();
 32	  const { createModal } = useModal();
 33	
 34	  const vmAttachedSecretName = useMemo(() => getVMSSHSecretName(vm), [vm]);
 35	
 36	  const [sshDetails, setSSHDetails] = useState<SSHSecretDetails>(
 37	    getInitialSSHDetails({
 38	      applyKeyToProject: tabsData.applySSHToSettings,
 39	      secretToCreate: tabsData.additionalObjects?.find((obj) => obj?.kind === SecretModel.kind),
 40	      sshSecretName: vmAttachedSecretName,
 41	    }),
 42	  );
 43	
 44	  const onSubmit = useCallback(
 45	    async (details: SSHSecretDetails) => {
 46	      const { applyKeyToProject, secretOption, sshPubKey, sshSecretName } = details;
 47	
 48	      if (isEqualObject(details, sshDetails)) {
 49	        return;
 50	      }
 51	
 52	      removeSSHKeyObject(updateTabsData, sshDetails.sshSecretName);
 53	      updateTabsData((currentTabsData) => {
 54	        currentTabsData.authorizedSSHKey = sshSecretName;
 55	        currentTabsData.applySSHToSettings = applyKeyToProject;
 56	      });
 57	
 58	      if (
 59	        secretOption === SecretSelectionOption.none &&
 60	        sshDetails.secretOption !== SecretSelectionOption.none
 61	      ) {
 62	        await updateVM(removeSecretToVM(vm));
 63	      }
 64	
 65	      if (
 66	        secretOption === SecretSelectionOption.useExisting &&
 67	        sshDetails.sshSecretName !== sshSecretName &&
 68	        !isEmpty(sshSecretName)
 69	      ) {
 70	        await updateVM(addSecretToVM(vm, sshSecretName));
 71	      }
 72	
 73	      if (
 74	        secretOption === SecretSelectionOption.addNew &&
 75	        !isEmpty(sshPubKey) &&
 76	        !isEmpty(sshSecretName)
 77	      ) {
 78	        updateSSHKeyObject(vm, updateTabsData, sshPubKey, sshSecretName);
 79	        await updateVM(addSecretToVM(vm, sshSecretName));
 80	      }
 81	
 82	      setSSHDetails(details);
 83	      return Promise.resolve();
 84	    },
 85	    [sshDetails, updateTabsData, updateVM, vm],
 86	  );
 87	
 88	  return (
 89	    <WizardDescriptionItem
 90	      description={
 91	        <Stack hasGutter>
 92	          <div data-test="ssh-popover">
 93	            <Trans ns="plugin__kubevirt-plugin" t={t}>
 94	              <Text component={TextVariants.p}>Store the key in a project secret.</Text>
 95	              <Text component={TextVariants.p}>
 96	                The key will be stored after the machine is created
 97	              </Text>
 98	            </Trans>
 99	          </div>
100	          <SecretNameLabel secretName={vmAttachedSecretName} />
101	        </Stack>
102	      }
103	      onEditClick={() =>
104	        createModal((modalProps) => (
105	          <SSHSecretModal
106	            {...modalProps}
107	            initialSSHSecretDetails={sshDetails}
108	            namespace={getNamespace(vm)}
109	            onSubmit={onSubmit}
110	          />
111	        ))
112	      }
113	      isEdit
114	      label={<LinuxLabel />}
115	      showEditOnTitle
116	      testId="wizard-sshkey"
117	      title={t('Public SSH key')}
118	    />
119	  );
120	};
121	
122	export default SSHKey;

